INSERT INTO deals (
  user_id,
  journey_type,
  current_gate,
  league,
  industry,
  location,
  business_name,
  revenue,
  sde,
  ebitda,
  asking_price,
  exit_type,
  financials,
  status,
  created_at,
  updated_at
)
SELECT
  o.id,
  i.journey_type,
  i.current_gate,
  i.league,
  i.industry,
  i.location,
  i.business_name,
  i.revenue_cents,
  i.sde_cents,
  i.sde_cents,                 -- ebitda mirrors sde for this sample data
  i.asking_cents,
  i.exit_type,
  jsonb_build_object(
    'sample_id',       i.sample_id,
    'deal_type_label', i.deal_type_label,
    'status_label',    i.status_label,
    'multiple',        i.multiple,
    'notes',           i.notes,
    'est_close',       i.est_close,
    'seed_source',     'SMBX_SAMPLE_DEALS_500_PAUL_BAKER'
  ),
  i.deal_status,
  COALESCE(NULLIF(i.created_at, '')::timestamptz, NOW()),
  NOW()
FROM incoming i
CROSS JOIN owner o
WHERE NOT EXISTS (
  SELECT 1 FROM deals d
  WHERE d.user_id = o.id
    AND d.financials->>'sample_id' = i.sample_id
);
